<?php/****************************** * Change password form page. * ******************************/require_once('../assets/db_inc_samen_emailpassf.php');require_once('../assets/db_inc_samen_loginf.php');if (!user_isloggedin()) {  header("Location: samen_index.php");}if ($_POST['submit'] == "Change my password") {  $feedback = user_change_password();  if ($feedback == 1) {    $feedback_str = "<P class=\"errormess\">Password changed</P>";  } else {    $feedback_str = "<P class=\"errormess\">$feedback</P>";  }}// ------------// DISPLAY FORM// ------------include_once('db_header_footer.php');site_header('Change Password');// Superglobals don't work with heredoc$php_self = $_SERVER['PHP_SELF'];$form_str = <<< EOFORMSTR<TABLE CELLPADDING=0 CELLSPACING=0 BORDER=0 ALIGN=CENTER WIDTH=621><TR> <TD>$feedback_str<P CLASS=left><B>Change your password</B><BR><FORM ACTION="$php_self" METHOD="POST"><B>Old password</B><BR><INPUT TYPE="password" NAME="old_password" VALUE="" SIZE="10" MAXLENGTH="15"><BR><BR><B>New Password</B><BR><INPUT TYPE="password" NAME="new_password1" VALUE="" SIZE="10" MAXLENGTH="15"><BR><BR><B>New password</B> (again)<BR><INPUT TYPE="password" NAME="new_password2" VALUE="" SIZE="10" MAXLENGTH="15"><BR><BR><INPUT TYPE="SUBMIT" NAME="submit" VALUE="Change my password"></FORM> </TD></TR></TABLE>EOFORMSTR;echo $form_str;site_footer();?>